AGENT_PALETTE: list[str] = [
    "#1FD5F9",
    "#09C338",
    "#1F5DF9",
    "#BA1FF9",
    "#F9AE1F",
    "#FA4C39",
]


def _agent_style(name: str) -> Style:
    h = hashlib.blake2b(name.encode("utf-8"), digest_size=2).digest()
    idx = int.from_bytes(h, "big") % len(AGENT_PALETTE)
    return Style(color=AGENT_PALETTE[idx], bold=True)


def _truncate_text(text: str, max_lines: int = 2, width: int = 80) -> str:
    wrapped = textwrap.wrap(text, width=width)

    if len(wrapped) <= max_lines:
        return "\n".join(wrapped)

    head_count = max_lines - 2
    head = wrapped[:head_count]
    tail = wrapped[-1:]

    return "\n".join(head + ["..."] + tail)


def _format_duration_ms(seconds: float) -> str:
    ms = seconds * 1000
    if ms >= 10:
        return f"{ms:.0f}ms"
    elif ms >= 1:
        return f"{ms:.1f}ms"
    else:
        return f"{ms:.2f}ms"


def _format_turn_metrics(
    user_metrics: llm.MetricsReport | None,
    assistant_metrics: llm.MetricsReport | None,
) -> Text | None:
    parts: list[tuple[str, str]] = []

    # user-side metrics
    if user_metrics:
        if "end_of_turn_delay" in user_metrics:
            v = user_metrics["end_of_turn_delay"]
            parts.append(("end_of_turn: ", "dim"))
            parts.append((_format_duration_ms(v), "dim"))
        if "on_user_turn_completed_delay" in user_metrics:
            v = user_metrics["on_user_turn_completed_delay"]
            parts.append(("turn_completed_cb: ", "dim"))
            parts.append((_format_duration_ms(v), "dim"))

    # assistant-side metrics
    if assistant_metrics:
        if "llm_node_ttft" in assistant_metrics:
            v = assistant_metrics["llm_node_ttft"]
            parts.append(("llm_ttft: ", "dim"))
            parts.append((_format_duration_ms(v), "dim"))
        if "tts_node_ttfb" in assistant_metrics:
            v = assistant_metrics["tts_node_ttfb"]
            parts.append(("tts_ttfb: ", "dim"))
            parts.append((_format_duration_ms(v), "dim"))
    e2e_parts: list[tuple[str, str]] = []
    if assistant_metrics and "e2e_latency" in assistant_metrics:
        v = assistant_metrics["e2e_latency"]
        e2e_parts.append(("e2e: ", "dim"))
        e2e_parts.append((_format_duration_ms(v), "red" if v >= 1.0 else "dim"))

    if not parts and not e2e_parts:
        return None

    assembled: list[tuple[str, str]] = []
    pair_count = len(parts) // 2
    for i in range(pair_count):
        if i > 0:
            assembled.append((" \u00b7 ", "dim"))
        assembled.append(parts[i * 2])  # label
        assembled.append(parts[i * 2 + 1])  # value

    if e2e_parts:
        if assembled:
            assembled.append(("  \u2500  ", "dim"))
        assembled.extend(e2e_parts)

    return Text.assemble(*assembled)


def _print_run_event(
    c: AgentsConsole,
    event: RunEvent,
    last_user_metrics: llm.MetricsReport | None = None,
) -> None:
    if event.type == "function_call":
        c.console.print()
        c.console.print(
            Text.assemble(
                ("  \u279c ", "#1FD5F9"),
                (event.item.name, "bold #1FD5F9"),
            )
        )
    elif event.type == "function_call_output":
        output = event.item.output
        display_output = output
        is_error = output.lower().startswith("error") or output.lower().startswith("exception")

        if not is_error:
            try:
                import json

                json_start = output.find("{")
                if json_start >= 0:
                    json_str = output[json_start:]
                    data = json.loads(json_str)
                    if isinstance(data, dict):
                        summary_parts = []
                        for k, v in data.items():
                            if v is not None and k != "type":
                                summary_parts.append(f"{k}={v}")
                        display_output = ", ".join(summary_parts[:3])
                        if len(summary_parts) > 3:
                            display_output += ", ..."
            except (json.JSONDecodeError, TypeError, ValueError):
                display_output = _truncate_text(output, max_lines=2)

        if is_error:
            c.console.print(
                Text.assemble(
                    ("    \u2717 ", "#EF4444"),
                    (_truncate_text(output, max_lines=2), "#EF4444"),
                )
            )
        else:
            c.console.print(
                Text.assemble(
                    ("    \u2713 ", "#6BCB77"),
                    (display_output, "dim"),
                )
            )
    elif event.type == "agent_handoff":
        old_agent = event.old_agent
        new_agent = event.new_agent

        old_style = _agent_style(old_agent.__class__.__name__)
        new_style = _agent_style(new_agent.__class__.__name__)
        c.console.print(
            Text.assemble(
                ("  \u25cf ", "#FFD93D"),
                ("Handoff: ", "bold #FFD93D"),
                Text(f"{old_agent.__class__.__name__}", style=old_style),
                (" \u2192 ", "dim"),
                Text(f"{new_agent.__class__.__name__}", style=new_style),
            )
        )

    elif event.type == "message":
        if event.item.text_content:
            c.console.print()
            c.console.print(
                Text.assemble(
                    ("  \u25cf ", "#6BCB77"),
                    ("Agent", "bold #6BCB77"),
                )
            )
            for line in event.item.text_content.split("\n"):
                c.console.print(Text(f"    {line}"))

            metrics_text = _format_turn_metrics(
                last_user_metrics if event.item.role == "assistant" else None,
                event.item.metrics if event.item.role == "assistant" else None,
            )
            if metrics_text is not None:
                metrics_line = Text("    ")
                metrics_line.append_text(metrics_text)
                c.console.print(metrics_line)
    else:
        logger.warning(f"unknown RunEvent type {event.type}")


def _audio_mode(c: AgentsConsole, *, input_device: str | None, output_device: str | None) -> None:
    ctrl_t_e = threading.Event()
    visualizer: FrequencyVisualizer | None = None

    def _listen_for_keys() -> None:
        while not ctrl_t_e.is_set():
            ch = readkey()
            if ch == key.CTRL_T:
                ctrl_t_e.set()
                break
            elif ch == "?" and visualizer is not None:
                visualizer.show_shortcuts = not visualizer.show_shortcuts
            elif ch == key.ESC and visualizer is not None:
                visualizer.show_shortcuts = False

    listener = threading.Thread(target=_listen_for_keys, daemon=True)
    listener.start()

    c.set_microphone_enabled(True, device=input_device)
    c.set_speaker_enabled(True, device=output_device)

    visualizer = FrequencyVisualizer(c, label=c.input_name or "unknown")
    visualizer.update()

    with Live(visualizer, console=c.console, refresh_per_second=12, transient=True):
        while not ctrl_t_e.is_set():
            visualizer.update()
            time.sleep(0.05)

    c.set_microphone_enabled(False)
    c.set_speaker_enabled(False)

    if ctrl_t_e.is_set():
        raise _ToggleMode()


class _ConsoleWorker:
    def __init__(self, *, server: AgentServer, shutdown_cb: Callable) -> None:
        self._loop = asyncio.new_event_loop()
        self._server = server
        self._shutdown_cb = shutdown_cb
        self._lock = threading.Lock()
        self._closed = False

    def start(self) -> None:
        self._thread = threading.Thread(target=self._worker_thread)
        self._thread.start()

    def join(self) -> None:
        self._thread.join()

    def shutdown(self) -> None:
        with self._lock:
            asyncio.run_coroutine_threadsafe(self._server.aclose(), self._loop)

    def _worker_thread(self) -> None:
        asyncio.set_event_loop(self._loop)

        async def _async_main() -> None:
            with self._lock:
                if self._closed:
                    self._shutdown_cb()
                    return

            self._server._job_executor_type = JobExecutorType.THREAD  # TODO: better setter

            @self._server.once("worker_started")
            def _simulate_job() -> None:
                asyncio.run_coroutine_threadsafe(
                    self._server.simulate_job(
                        "console-room", agent_identity="console", fake_job=True
                    ),
                    self._loop,
                )

            await self._server.run(devmode=True, unregistered=True)
            self._shutdown_cb()

        self._loop.run_until_complete(_async_main())


def _run_console(
    *,
    server: AgentServer,
    input_device: str | None,
    output_device: str | None,
    mode: ConsoleMode,
    record: bool,
    log_level: int | str = logging.DEBUG,
) -> None:
    c = AgentsConsole.get_instance()
    c.console_mode = mode
    c.enabled = True
    c.record = record

    _configure_logger(c, log_level)
    c.print("Starting console mode 🚀", tag="Agents")

    if c.record:
        c.print(
            f"Session recording will be saved to {c.session_directory}",
            tag="Recording",
            tag_style=Style.parse("black on red"),
        )

    c.print(" ")
    # c.print(
    #     "Searching for package file structure from directories with [blue]__init__.py[/blue] files"
    # )
    try:
        # import_data = get_import_data(path=path)
        # c.print(f"Importing from {import_data.module_data.extra_sys_path}")
        # c.print(" ")

        c._validate_device_or_raise(input_device=input_device, output_device=output_device)

        exit_triggered = False

        def _on_worker_shutdown() -> None:
            try:
                signal.raise_signal(signal.SIGTERM)
            except Exception:
                try:
                    signal.raise_signal(signal.SIGINT)
                except Exception:
                    pass

        def _handle_exit(sig: int, frame: FrameType | None) -> None:
            nonlocal exit_triggered
            if not exit_triggered:
                exit_triggered = True
                raise _ExitCli()

            console_worker.shutdown()

        for sig in HANDLED_SIGNALS:
            signal.signal(sig, _handle_exit)

        console_worker = _ConsoleWorker(server=server, shutdown_cb=_on_worker_shutdown)
        console_worker.start()

        # TODO: wait for a session request the agents console context before showing any of the mode
        try:
            c.wait_for_io_acquisition()

            while True:
                try:
                    if c.console_mode == "text":
                        _text_mode(c)
                    elif c.console_mode == "audio":
                        _audio_mode(c, input_device=input_device, output_device=output_device)

                except _ToggleMode:
                    c.console_mode = "audio" if c.console_mode == "text" else "text"

        except _ExitCli:
            pass
        finally:
            console_worker.shutdown()
            console_worker.join()

    except (CLIError, ValueError) as e:
        c.print(" ")
        c.print(f"[error]{e}")
        c.print(" ")
        raise typer.Exit(code=1) from None


def _run_worker(server: AgentServer, args: proto.CliArgs, jupyter: bool = False) -> None:
    c: AgentsConsole | None = None
    if args.devmode:
        c = AgentsConsole.get_instance()  # colored logs

    exit_triggered = False

    if not jupyter:

        def _handle_exit(sig: int, frame: FrameType | None) -> None:
            nonlocal exit_triggered
            if not exit_triggered:
                exit_triggered = True
                raise _ExitCli()

        for sig in HANDLED_SIGNALS:
            signal.signal(sig, _handle_exit)

    _configure_logger(c, args.log_level)

    loop = asyncio.new_event_loop()
    asyncio.set_event_loop(loop)

    loop.slow_callback_duration = 0.1  # 100ms

    async def _worker_run(worker: AgentServer) -> None:
        try:
            await server.run(devmode=args.devmode, unregistered=jupyter)

        except Exception:
            logger.exception("worker failed")

    watch_client = None
    if args.reload:
        from .watcher import WatchClient

        watch_client = WatchClient(server, args, loop=loop)
        watch_client.start()

    try:
        main_task = loop.create_task(_worker_run(server), name="worker_main_task_cli")
        try:
            loop.run_until_complete(main_task)
        except _ExitCli:
            pass

        try:
            exit_triggered = False  # allow a new _ExitCLI raise
            if not args.devmode:
                try:
                    loop.run_until_complete(server.drain())
                except asyncio.TimeoutError:
                    logger.warning("drain timed out, forcing shutdown")

            loop.run_until_complete(server.aclose())

            if watch_client:
                loop.run_until_complete(watch_client.aclose())
        except _ExitCli:
            if not jupyter:
                logger.warning("exiting forcefully")
                import os

                os._exit(1)  # TODO(theomonnom): add aclose(force=True) in worker
    finally:
        if jupyter:
            loop.close()  # close can only be called from the main thread
        else:
            with contextlib.suppress(_ExitCli):
                try:
                    tasks = asyncio.all_tasks(loop)
                    for task in tasks:
                        task.cancel()

                    loop.run_until_complete(asyncio.gather(*tasks, return_exceptions=True))
                finally:
                    loop.run_until_complete(loop.shutdown_asyncgens())
                    loop.run_until_complete(loop.shutdown_default_executor())
                    loop.close()


